INSERT INTO alert_rules (id, name, description, status, kind, severity, target_scope, cooldown_seconds, reopen_after_seconds, evaluation_interval_seconds, window_seconds, condition, labels, metadata, created_by, created_at, updated_at) VALUES
    ('rule-high-cpu', 'High CPU Usage', 'CPU usage above 80% for 5 minutes', 'active', 'metric_threshold', 'medium', 'global', 300, 60, 30, 300, '{"metric":"cpu_percent","operator":">","threshold":80}'::jsonb, '{"category":"performance"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-disk-full', 'Disk Nearly Full', 'Disk usage above 90%', 'active', 'metric_threshold', 'critical', 'global', 300, 60, 30, 60, '{"metric":"disk_percent","operator":">","threshold":90}'::jsonb, '{"category":"capacity"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-mem-pressure', 'Memory Pressure', 'Memory usage above 85% for 10 minutes', 'active', 'metric_threshold', 'high', 'global', 600, 60, 30, 600, '{"metric":"memory_percent","operator":">","threshold":85}'::jsonb, '{"category":"performance"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-offline', 'Node Offline', 'Node has not reported in 5 minutes', 'active', 'heartbeat_stale', 'critical', 'global', 300, 60, 60, 300, '{"stale_seconds":300}'::jsonb, '{"category":"availability"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-svc-down', 'Service Down', 'Critical service process not detected', 'active', 'log_pattern', 'critical', 'global', 120, 30, 30, 120, '{"pattern":"service (stopped|crashed|exited)","level":"error"}'::jsonb, '{"category":"availability"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-cert-expiry', 'Certificate Expiring', 'TLS certificate expires within 14 days', 'active', 'metric_threshold', 'high', 'global', 3600, 60, 3600, 86400, '{"metric":"cert_days_remaining","operator":"<","threshold":14}'::jsonb, '{"category":"security"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-backup-stale', 'Backup Stale', 'No successful backup in 36 hours', 'active', 'metric_deadman', 'high', 'global', 3600, 60, 3600, 129600, '{"metric":"backup_last_success_hours","threshold":36}'::jsonb, '{"category":"data-protection"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00'),
    ('rule-net-latency', 'Network Latency High', 'Inter-node latency above 50ms for 3 minutes', 'active', 'metric_threshold', 'medium', 'global', 300, 60, 30, 180, '{"metric":"net_latency_ms","operator":">","threshold":50}'::jsonb, '{"category":"network"}'::jsonb, '{}'::jsonb, 'admin', '2026-02-15 04:28:00+00', '2026-02-15 04:28:00+00')
